var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"기상청은 오늘 돌발적으로 내리기 시작한 집중호우가 내일까지 이어질 것이라고 밝혔습니다.","JPN":"気象庁の発表によりますと、本日突発的に降り出した集中豪雨は明日まで続く見込みです。","ENG":"According to the meteorological administration, the heavy downpours that began unexpectedly today will continue into tomorrow.","TWN":"氣象局今天發布局部豪雨特報，這一波雨勢預計會持續至明天。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"저녁 내내 천둥, 번개를 동반한 비바람이 몰아칠 것으로 예상되오니 주무시기 전에…….","JPN":"夜には雷を伴った暴風雨が予想されますので、お休み前には……","ENG":"Rain and wind are expected throughout the evening, along with thunder and lightning, so we urge you t-","TWN":"入夜後預計風雨將伴隨閃電而至，入睡前請……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"의무관은…… 없나?","JPN":"医務官は……留守か？","ENG":"The medic... is on a break, I suppose.","TWN":"醫務官……人呢？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오히려 다행이라면 다행이군.","JPN":"むしろ幸いというべきかな。","ENG":"Perhaps it is for the best.","TWN":"希望是我多心了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"……음.","JPN":"……うむ。","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"우으……?","JPN":"うう……？","ENG":"Hmm?","TWN":"呃呃……？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오랜만이에요. 여전히 연기에 몰두하고 있군요.","JPN":"お久しぶりです。相変わらず芝居熱心ですね。","ENG":"Long time no see. Still pretending, are you?","TWN":"好久不見，你還是演得很認真呢。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 이미 충분히 조사하고 왔어요. 시간이 없으니 단도직입적으로 묻겠습니다.","JPN":"ですが、もう十分調査してきました。時間がないので単刀直入に聞きます。","ENG":"However, I have done my research. I do not have time, so I will ask you directly.","TWN":"不過我是充分調查過後才來的，時間不多，我就直接發問。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신은…… <color=#ffd34c>누구</color>입니까?","JPN":"あなたは……<color=#ffd34c>誰</color>ですか？","ENG":"Who... are <color=#ffd34c>you</color>?","TWN":"你……<color=#ffd34c>是誰</color>？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"……아. ……으음.","JPN":"……あ。……うう。","ENG":"Ah... Mm...","TWN":"……啊……嗯。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대답하기 싫다면 질문을 바꾸죠.","JPN":"答えたくなければ、質問を変えましょう。","ENG":"If you do not wish to answer, allow me to change the question.","TWN":"不想回答的話，那我換個問題。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그릇으로서 당신의 육신이 품고 있는 그것은 <color=#ffd34c>무엇</color>입니까?","JPN":"器としてのあなたが持っているそれは<color=#ffd34c>何</color>ですか？","ENG":"<color=#ffd34c>What</color> is it within you that is using you as a vessel?","TWN":"身為一個器皿，你懷裡抱著的是<color=#ffd34c>什麼</color>東西？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"여전히 대답할 생각이 없나 보군요. 당신도. 당신 안에 있는 무언가도.","JPN":"相変わらず答える気はないようですね。あなたも。あなたの中にいる何かも。","ENG":"Still not thinking about answering, I see. You nor the thing inside you.","TWN":"關於你的身分和你懷裡的東西，你都不願意回答嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"좋습니다. 그럼 제 방식대로 읽어내 드리죠.","JPN":"いいでしょう。それでは私のやり方で読ませていただきます。","ENG":"Very well, then I shall read you my way.","TWN":"很好，那我就照我的方式讀囉。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대정화 전쟁 이후, 관리 거부 구역에서 집행됐던 성무들의 보고서를 모두 열람해 봤습니다.","JPN":"大浄化戦争以後、管理拒否区域で執行された聖務の報告書をすべて閲覧してみました。","ENG":"After the Grand Purification War, I have read every single report of the sacred missions carried out in the Anti-Administration Zone.","TWN":"我已經讀完淨化之戰之後，在拒絕管理區域執行過的聖務相關報告。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그리고 보고서를 읽으면서 한 가지 흥미로운 점을 발견할 수 있었죠.","JPN":"そして報告書を読みながら、一点、興味深いものを発見しました。","ENG":"And as I read the report, I noticed something interesting.","TWN":"然而，在我讀的過程，發現一個有趣的點。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"최근 몇 년간, 사교도들 사이에서 인간을 제물로 바치는 사례가 부쩍 늘어났더군요.","JPN":"この数年間、邪教徒の間で人間を生贄に捧げる事例がぐっと増えていたのです。","ENG":"Human sacrifice has become extremely prevalent among cults in recent years.","TWN":"就是最近幾年，邪教徒拿人當祭物獻祭的事一下子增加許多。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"사교도들에게도 시기별로 유행이라는 게 존재하나 보죠?","JPN":"邪教徒にも時期によって流行りがあるようですね？","ENG":"Does this imply that there are cult-specific trends?","TWN":"對邪教徒而言也有所謂的旺季嗎？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"으으…….","JPN":"むう……","ENG":"Err...","TWN":"呃……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"상식적으로 그럴 리 없습니다. 조직적인 개입 없이는 불가능해요.","JPN":"常識的に考えればそんなはずがありません。組織的な介入なしでは不可能です。","ENG":"That, however, does not make sense. Without organizational intervention, it is impossible.","TWN":"理論上是沒有，若非有組織地介入是不可能的。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 루퍼의 사례처럼, 어떤 조건에 부합하는 희생양을 최대한 확보하기 위해…….","JPN":"シスタールーパーの例のように、ある条件に相応しい人柱を最大限確保するために……","ENG":"Much like Sister Looper's case, in order to secure as many sacrifices as possible that meet certain criteria...","TWN":"像是洛珀姊妹的例子，若要大量取得符合某種條件的犧牲羊……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"아, 아아…… 아아아아……","JPN":"あ、あ……ああああ……","ENG":"Ah... Aaah... Aaaaahhh...","TWN":"啊啊啊……啊啊啊啊……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런 이야기 들어 보셨나요?","JPN":"こんな話、聞いたことがありますか？","ENG":"Have you heard of this story before?","TWN":"你聽過這個故事嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어떤 나라는 순결한 어린 여자아이를 선별해 살아 있는 여신으로 섬긴다고 합니다.","JPN":"とある国では純潔な少女を選別し、生きた女神とし崇めるそうです。","ENG":"In some countries, innocent young girls are selected to be worshiped as living goddesses.","TWN":"據說在某個國家，會揀選純潔的童女，作為侍奉的活女神。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 조건은 나이만이 아니에요. 외모, 가문, 품행 등 까다로운 심사를 거쳐야 하죠.","JPN":"ですが、選別の条件は歳だけではありません。外見、家柄、品行などの厳しい審査が行われます。","ENG":"But age is not the only restriction. They are chosen after a thorough screening of their appearance, family background, and behavior.","TWN":"但獲選的條件不只是年齡，包括長相、家世背景、品行等等，都必須經過嚴苛的審查。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"신이 깃들 그릇을 선별하는 과정이니 조건이 까다로운 것도 이해가 됩니다만.","JPN":"神が宿る器を選別する段階ですので、条件が厳しいのもわかりますが。","ENG":"It is understandable as they are selecting a vessel for a goddess to reside in.","TWN":"條件嚴苛是可以理解的，畢竟是要選出神要使用的器皿。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"학회도 그들이 섬기던 <color=#ffd34c>무언가</color>를 부르기 위해 당신들의 마을에서 그런 짓을 저지른 것 아닌가요?","JPN":"学会も崇めていた<color=#ffd34c>何か</color>を呼ぶために、あなたたちの村で似たようなことをやっていたのではないですか？","ENG":"Isn't that why the Society committed such heinous acts in your village in order to summon <color=#ffd34c>that thing</color> they worship?","TWN":"這不就是學會為要召喚出他們所侍奉的<color=#ffd34c>某個存在</color>，而在你們的村莊裡做的事嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"하…….","JPN":"は……","ENG":"Haa...","TWN":"呼……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결과적으로 마지막에는 당신이 선별되었을 겁니다.","JPN":"結果として最終的にあなたが選ばれたはずです。","ENG":"Ultimately, you were the one to be selected.","TWN":"結論而言，就是最後被選上的是你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 문제가 생겼습니다. 뒤늦게 당신보다 조건에 부합하는 사람이 나타난 거죠.","JPN":"ですが問題が発生しました。後からあなたより条件に合う人が現れたのです。","ENG":"However, there was a problem. They found someone better suited than you.","TWN":"但後來卻發生一個問題，就是之後又出現另一個比你更符合條件的人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"……큽.","JPN":"……くっ。","ENG":"...Pfft...","TWN":"……咳。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"크큭, 키힉! 크히힛……!","JPN":"くくっ、きひっ！　ぐひひっ……！","ENG":"Kek... Kek! Kehehe...!","TWN":"咳咳咳！咳咳……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L21_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"언니 진짜 멍청하다. 아무것도 모르는 주제에 다 아는 듯이 떠드네?","JPN":"お姉ちゃん、本当バカだね。何も知らないくせに、全部知ってるかのように喋ってるじゃん。","ENG":"Wow, you're incredibly stupid. You speak as if you know everything, but you don't know a thing!","TWN":"姊姊真傻，明明什麼都不知道，卻又表現得好像什麼都知道一樣。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"唔……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어, 어째서……! 숨이……!","JPN":"ど、どうして……！ 息が……！","ENG":"I… I can't breath...?!","TWN":"我的呼吸……！怎麼會……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"괜찮아. 말하지 않아도 돼.","JPN":"大丈夫。言わなくてもわかるよ。","ENG":"It's all right. You don't need to talk.","TWN":"沒事的，別說話。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"신부 오빠가 그 곳에서 뭘 했는지 알고 싶은 거잖아?","JPN":"神父のお兄ちゃんがそこで何をしたのか知りたいんでしょう？","ENG":"You just wanna know what the Father did over there, right?","TWN":"你不是想知道神父哥哥在那做了什麼嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"원한다면 언니한테도 보여 줄게. 신부 오빠가 뭘 봤는지.","JPN":"お望みならお姉ちゃんにも見せてあげるよ。神父のお兄ちゃんが何を見たのか。","ENG":"If you want, I'll show you what the Father saw.","TWN":"你想知道的話，我也可以讓你看看神父哥哥到底看到什麼。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……대답해다오, 마왕의 권속이여.","JPN":"……答えてくれ、魔王の眷属よ。","ENG":"Heed my call, kin of the Demon Lord.","TWN":"……魔王的手下還真厲害。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"내가 여지껏 찾던 구원은……  모조리 허황된 것이란 말인가?","JPN":"今まで私が探していた救いは……すべて絵空事だったのか？","ENG":"The salvation I have been looking for... Was it all for naught?","TWN":"難道我過去所追求的救贖……到頭來只是一場空嗎？"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"허억……! 하……! 우윽……!","JPN":"はあっ……！　は……！　ううっ……！","ENG":"*Gasp...!* *Pant* *Pant*","TWN":"呼呼……！呼……呃呃……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L46_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"미치지 않았네? 의지가 꽤 강하구나, 언니?","JPN":"狂わないんだね？　お姉ちゃん、結構意志が強いんだ。","ENG":"Hey, you didn't go crazy. You're stronger than you look, Sister.","TWN":"姊姊，你還沒精神錯亂嗎？意志力蠻堅強的嘛～"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"불쌍한 맥크레디. 안나의 죄라면 자기를 담을 그릇을 너무 열심히 준비했다는 거야.","JPN":"可哀想なマクレディー。アンナの罪は自分を宿る器を準備するのに頑張りすぎたってことよ。","ENG":"Poor MacCready. Her only sin was that she went overboard preparing her vessels.","TWN":"可憐的麥克蕾蒂，若全是安娜的，那她未免也太認真預備她的器皿。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"그림자에 혹해 자신의 옹졸한 정신을 담기에는 너무 큰 그릇들을 만들어 버렸지.","JPN":"シャドウに惑わされて、自分の小っちゃい精神を宿すには大きすぎる器を作っちゃった。","ENG":"She was enticed by Shadows and created vessels that were too large for her small mind.","TWN":"受到暗影的迷惑，預備這麼多要盛裝自己薄弱意念的器皿。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"자리를 마련해 두는 건 불러선 안 될 것들을 부르는 짓인 줄 알면서도.","JPN":"場所を作っておくというのは、呼んではいけないものを呼ぶことだって知ってたくせにね。","ENG":"She was well aware that by creating empty vessels, she would summon things that were not meant to be summoned.","TWN":"孰不知，預備這些器皿，卻召喚出不該召喚的存在。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"너……. 전부 안다는 듯이 떠드는군.","JPN":"あなた……全部知ってるかのように話すのね。","ENG":"You... speak as if you know everything.","TWN":"你……好像什麼都知道是吧。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇다면 묻겠다. 그러는 너의 이름은 무엇이냐.","JPN":"それなら問う。お前の名は何だ。","ENG":"Then allow me to ask. What is your name?","TWN":"那我問你，你叫什麼名字！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"으음?","JPN":"ううん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"언니, 설마 그걸 구마 의식이라고 하는 거야? 내가 그렇게 겁나?","JPN":"お姉ちゃん、まさかそれエクソシズムなの？　そんなに私が怖い？","ENG":"Hey, you call that an exorcism? What? Do I scare you?","TWN":"姊姊，你該不會是要進行驅魔儀式吧？我有這麼可怕嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말하라! 심연 속에 똬리 틀고 있는 자, 너의 이름은 무엇이냐!","JPN":"言え！　深淵に居座る者、お前の名は何だ！","ENG":"Answer me! One who twists within the abyss, I demand thy name!","TWN":"說！在深淵裡盤繞的人，你叫什麼名字！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"<color=#ff3636>소용없어. 애초에 난 언니가 생각하는 악마 따위가 아닌걸.</color>","JPN":"<color=#ff3636>無駄だよ。そもそも私はお姉ちゃんが思う悪魔なんかじゃないんだから。</color>","ENG":"<color=#ff3636>It's no use. For one, I'm not the devil you think I am.</color>","TWN":"<color=#ff3636>沒用的，我不是你以為的魔鬼。</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"<color=#ff3636>그러니 포기해. 소리친다고 내가 겁먹을 것 같아?</color>","JPN":"<color=#ff3636>だから諦めて。いくら叫んでも怖くないから。</color>","ENG":"<color=#ff3636>So just give up. Do you think shouting will intimidate me?</color>","TWN":"<color=#ff3636>我勸你還是放棄吧，你以為這樣吼二句我就會怕你嗎？</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말하라……! 들끓는 파리 떼 속에 숨은 자여!","JPN":"言え……！　たかるハエの群れに隠れた者よ！","ENG":"Answer me...! The one who hides among the crawling swarm of flies!","TWN":"說……！躲在蒼蠅群裡的人！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"<color=#ff3636>슬슬 성무 SI3E의 윤곽이 읽히기 시작하는군요.</color>","JPN":"<color=#ff3636>そろそろ聖務SI3Eの輪郭が読めてきましたね。</color>","ENG":"<color=#ff3636>The outline of Sacred Mission SI3E is starting to become legible.</color>","TWN":"<color=#ff3636>聖務SI3E的輪廓似乎越來越清晰。</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"<color=#ff3636>결론을 읽어내는 건 접니다. 그건 당신이 걱정할 문제가 아니죠.</color>","JPN":"<color=#ff3636>結論を読み取るのは私です。それはあなたが心配する問題ではありません。</color>","ENG":"<color=#ff3636>You have nothing to be concerned about. I will be the one who reads the end.</color>","TWN":"<color=#ff3636>結論是由我來讀的，不需要你費心。</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"<color=#ff3636>힉…….</color>","JPN":"<color=#ff3636>ひッ……！</color>","ENG":"<color=#ff3636>Kek...</color>","TWN":"<color=#ff3636>嘻……</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"<color=#ff3636>히힉……! 히히히힉……!</color>","JPN":"<color=#ff3636>ひひっ……！　ひひひひっ……！</color>","ENG":"<color=#ff3636>Keek...! Kekekekeek...!</color>","TWN":"<color=#ff3636>嘻嘻……！嘻嘻嘻嘻……！</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>두려워 말라. 자신이 신을 믿는다고 착각하는 어리석은 여자야.</color>","JPN":"<color=#ff3636>恐れるな。神を信じていると勘違いしている愚かな女よ。</color>","ENG":"<color=#ff3636>Don’t be afraid, oh foolish girl who thinks she believes in God.</color>","TWN":"<color=#ff3636>別怕，誤以為自己信神的蠢女人。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>나의 주인께서는 오직 치밀한 겹눈으로 세상만물의 흥망을 관조하시는 자.</color>","JPN":"<color=#ff3636>我が主はただ緻密な複眼で世界万物の興亡を観照する者。</color>","ENG":"<color=#ff3636>It is my Master who, with keen compound eyes, contemplates the rise and fall of this world.</color>","TWN":"<color=#ff3636>我的主人是以縝密的複眼來觀察世界興衰之人。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>나는 눈먼 네가 부르짖는 신의 뜻을 따라 여기에 당도하였노라.</color>","JPN":"<color=#ff3636>私は目の見えないお前が叫ぶ神の意に従い、ここへたどり着いた。</color>","ENG":"<color=#ff3636>For it was I who was summoned here when you blindly called out for your God.</color>","TWN":"<color=#ff3636>我是按瞎眼的你所召喚之神的旨意而來。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"subtitle","speaker":null,"text":{"KOREA":"성황청 구마회 성무 일지\\n부마자 – 비블리데 루체, 성황청 도서관 비밀 서고 담당 사서","JPN":"聖皇庁祓魔会聖務日誌\\n悪魔付き：ビブリデ・ルーチェ、聖皇庁図書館秘密書庫担当司書","ENG":"Holy Curia's Sacred Exorcism Journal\\nBiblide Luce (possessed), librarian in charge of the Holy Curia library's secret archives","TWN":"聖皇廳驅魔會聖務日誌\\n附魔者 – 布莉黛·露契，聖皇廳圖書館秘密書庫負責人"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"부마자는 요한 추기경 암살 사건을 조사하던 중 격리 조치된 사교도와 접촉.\\n이후 현장에서 혼수 상태로 발견되었다.","JPN":"悪魔付きはヨハン枢機卿暗殺事件を調査する途中、隔離措置された邪教徒と接触。\\n以後、現場で昏睡状態で発見された。","ENG":"She came into contact with a quarantined cultist while investigating Cardinal Johan's assassination case.\\nWas later found in a coma at the scene.","TWN":"附魔者於調查約翰樞機主教遭暗殺一事時，與隔離中的邪教徒接觸。\\n之後遭人發現於現場昏迷不醒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"subtitle","speaker":null,"text":{"KOREA":"최초 발견 당시 전신에 다수의 창상 및 환부의 급격한 괴사를 확인했다.","JPN":"発見当初、全身に多数の創傷及び患部の急激な壊疽を確認した。","ENG":"At the time of the initial discovery, a number of injuries and rapid necrosis of the affected area were discovered throughout the body.","TWN":"發現當下，查看身上有多處創傷和患處快速壞死。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"subtitle","speaker":null,"text":{"KOREA":"의학적 조치와 구마의식을 병행한 결과, 증상이 호전되었다.","JPN":"医学的な処置とエクソシズムを並行した結果、症状が好転した。","ENG":"Symptoms improved as a result of the combination of medical measures and exorcism.","TWN":"在進行醫療措施與驅魔儀式後症狀好轉。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"subtitle","speaker":null,"text":{"KOREA":"부마자는 성무 SI3E에 대한 심문 도중 환각과 환청, 일시적인 기억 소실을 경험했다고 증언했다.","JPN":"悪魔付きは聖務SI3Eについての審問の途中に幻覚と幻聴、一時的な記憶喪失を経験したと証言した。","ENG":"During the Sacred Mission SI3E interrogation, she claimed to have experienced temporary memory loss as well as extreme audio and visual hallucinations.","TWN":"附魔者表示，在審問聖務SI3E的過程中，有發生幻覺、幻聽，與暫時消失記憶之情況。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"subtitle","speaker":null,"text":{"KOREA":"실종되었던 담당 의무관은 격리실에서 3km 떨어진 성당 첨탑에 감전사한 채 걸려 있었다.","JPN":"失踪した担当医務官は隔離室から3km離れた聖堂の尖塔の先に感電死した状態で発見された。","ENG":"Three kilometers away from the quarantine room, the missing medic in charge was discovered electrocuted and hanging from the cathedral spire.","TWN":"而失蹤之醫務官，屍體吊掛在距離隔離病房3km的教堂屋頂上，死因為觸電身亡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"심문을 진행한 격리실은 학계에 보고된 바 없는 파리목 생물의 대량 발생으로 소각 후 폐쇄 조치되었다.","JPN":"審問を行った隔離室は学会に報告されたことのないハエ目に属する生物の大量発生により、焼却後閉鎖された。","ENG":"The quarantine room used for the interrogation was incinerated and then closed after a mass breakout of an unknown fly species.","TWN":"在進行審問的隔離病房中，則發現大量雙翅目的生物，銷毀後已進行封鎖。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"부마자가 접촉한 사교도는 현재 실종 상태다.","JPN":"悪魔付きが接触した邪教徒は現在失踪状態である。","ENG":"The cultist who came in contact with her is currently missing.","TWN":"附魔者接觸之邪教徒目前下落不明。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};